#include <bits/stdc++.h>
using namespace std;
int n,q;
map<pair<int,int>,int> mp;
int main(){
    cin>>n>>q;
    while(q--){
        int op,i,j,k;
        cin>>op>>i>>j;
        if(op==1){
            cin>>k;
            mp[make_pair(i,j)]=k;
        }else
            printf("%d\n",mp[make_pair(i,j)]);
    }
    return 0;
}
